def backup_file(path: Path) -> None:
    if path.exists():
        rel = path.relative_to(ROOT)
        dest = BACKUP / rel
        dest.parent.mkdir(parents=True, exist_ok=True)
        shutil.copy2(path, dest)

def write_file(rel: str, content: str) -> None:
    path = ROOT / rel
    path.parent.mkdir(parents=True, exist_ok=True)
    backup_file(path)
    if rel.endswith("v17_55_live_intelligence_feed_narrative_flow.json"):
        data = json.loads(content)
        data["installed_at"] = datetime.now(timezone.utc).isoformat()
        content = json.dumps(data, indent=2)
    path.write_text(content, encoding="utf-8", newline="\n")

def main() -> None:
    for rel, content in FILES.items():
        write_file(rel, content)
    print("v17.55 — Live Intelligence Feed + Narrative Flow Layer installed.")
    print("Run:")
    print("  python -m pytest tests\\test_v17_55_live_intelligence_feed_narrative_flow.py")

if __name__ == "__main__":
    main()
